const input = $input.first().json;
const query = input.query || {};
const { search, estado, origen, lead_tipo, limit = 50, offset = 0 } = query;

const searchPattern = search ? `%${search}%` : '%';
const allowedEstados = ['NUEVO', 'FRIO', 'TIBIO', 'CALIENTE'];
const estadoFilter = estado && allowedEstados.includes(estado) ? estado : null;

let whereClause = `(nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')`;

if (estadoFilter) {
  whereClause += ` AND estado = '${String(estadoFilter).replace(/'/g, "''")}' `;
} else {
  whereClause += ` AND estado IN ('NUEVO','FRIO','TIBIO','CALIENTE')`;
}

if (origen) {
  whereClause += ` AND origen = '${String(origen).replace(/'/g, "''")}' `;
}

if (lead_tipo) {
  whereClause += ` AND lead_tipo = '${String(lead_tipo).replace(/'/g, "''")}' `;
}

const sqlList = `SELECT id, nombre, whatsapp, email, estado, nivel, origen, lead_tipo, objetivo, resumen, tags, primera_consulta, ultimo_contacto FROM leads WHERE ${whereClause} ORDER BY ultimo_contacto DESC NULLS LAST LIMIT ${parseInt(limit)} OFFSET ${parseInt(offset)};`;

const sqlCount = `SELECT COUNT(*) as total FROM leads WHERE ${whereClause};`;

return [{
  json: {
    sqlList,
    sqlCount
  }
}];

const listData = $('query_list').all();
const countData = $('query_count').all();
const total = countData[0]?.json?.total || 0;
const items = listData.map(row => row.json);

return [{
  json: {
    success: true,
    items: items,
    total: parseInt(total),
    count: items.length
  }
}];
